import type { Meta, StoryObj } from '@storybook/react-vite';
import { Space } from './Space';
import { Button } from '../Button';
import { Tag } from '../Tag';

const meta = {
  title: 'Components/Space',
  component: Space,
  tags: ['autodocs'],
  argTypes: {
    direction: { control: 'inline-radio', options: ['horizontal', 'vertical'] },
    size: { control: 'select', options: ['small', 'default', 'large'] },
    alignment: { control: 'inline-radio', options: ['start', 'end', 'center', 'baseline'] },
    wrap: { control: 'boolean' },
    fill: { control: 'boolean' },
    align: { table: { disable: true } },
  },
  args: {
    direction: 'horizontal',
    size: 'small',
  },
  render: (args) => (
    <Space {...args}>
      <Button type="primary">One</Button>
      <Button>Two</Button>
      <Button>Three</Button>
    </Space>
  ),
} satisfies Meta<typeof Space>;

export default meta;
type Story = StoryObj<typeof meta>;

export const Playground: Story = {};

export const Vertical: Story = {
  args: { direction: 'vertical', alignment: 'start' },
};

export const Sizes: Story = {
  render: () => (
    <Space direction="vertical" alignment="start" size="large">
      <Space size="small">
        <Tag>small</Tag>
        <Tag>small</Tag>
        <Tag>small</Tag>
      </Space>
      <Space size="default">
        <Tag>default</Tag>
        <Tag>default</Tag>
        <Tag>default</Tag>
      </Space>
      <Space size="large">
        <Tag>large</Tag>
        <Tag>large</Tag>
        <Tag>large</Tag>
      </Space>
    </Space>
  ),
};

export const Wrap: Story = {
  render: () => (
    <div style={{ width: 260 }}>
      <Space wrap>
        {Array.from({ length: 8 }, (_, i) => (
          <Tag key={i}>Tag {i + 1}</Tag>
        ))}
      </Space>
    </div>
  ),
};

import { type CSSProperties, forwardRef, type HTMLAttributes, type ReactNode } from 'react';
import { cls, useNamespace } from '../../utils';

export type SpaceDirection = 'horizontal' | 'vertical';

export type SpaceSize = 'small' | 'default' | 'large' | number;

export type SpaceAlign = 'start' | 'end' | 'center' | 'baseline';

export interface SpaceProps extends HTMLAttributes<HTMLDivElement> {
  /** Layout direction. */
  direction?: SpaceDirection;
  /** Spacing between items. Named sizes map to small=8, default=12, large=16. */
  size?: SpaceSize;
  /** Cross-axis alignment of items. Defaults to `center`. */
  alignment?: SpaceAlign;
  /**
   * Cross-axis alignment of items.
   * @deprecated Use `alignment` to match the Element Plus API. Kept as an alias.
   */
  align?: SpaceAlign;
  /** Whether items wrap onto multiple lines. */
  wrap?: boolean;
  /** Whether items stretch to fill the available space. */
  fill?: boolean;
  children?: ReactNode;
}

const sizeMap: Record<Exclude<SpaceSize, number>, number> = {
  small: 8,
  default: 12,
  large: 16,
};

const alignMap: Record<SpaceAlign, CSSProperties['alignItems']> = {
  start: 'flex-start',
  end: 'flex-end',
  center: 'center',
  baseline: 'baseline',
};

export const Space = forwardRef<HTMLDivElement, SpaceProps>(function Space(props, ref) {
  const {
    direction = 'horizontal',
    size = 'small',
    alignment,
    align,
    wrap = false,
    fill = false,
    className,
    style,
    children,
    ...rest
  } = props;

  const ns = useNamespace('space');

  const gap = typeof size === 'number' ? size : sizeMap[size];

  // `alignment` is the canonical prop; `align` is kept as a deprecated alias.
  const resolvedAlign: SpaceAlign = alignment ?? align ?? 'center';

  const classes = cls(
    ns.b(),
    ns.m(direction),
    ns.is('wrap', wrap),
    ns.is('fill', fill),
    className,
  );

  const spaceStyle: CSSProperties = {
    gap,
    alignItems: alignMap[resolvedAlign],
  };

  return (
    <div ref={ref} className={classes} style={{ ...spaceStyle, ...style }} {...rest}>
      {children}
    </div>
  );
});

.ec-space {
  box-sizing: border-box;
  display: inline-flex;
  flex-direction: row;
}

.ec-space--vertical {
  flex-direction: column;
}

.ec-space.is-wrap {
  flex-wrap: wrap;
}

.ec-space.is-fill {
  display: flex;
  width: 100%;
}

.ec-space.is-fill > * {
  flex: 1;
}
